const tables = $input.all().map(i => i.json);

if (tables.length === 0) {
  return [{ json: { found: 0, tables: [], summary: 'No orphaned temp tables found. Nothing to clean up.' } }];
}

const list = tables.map(t => `  - ${t.tablename} (${t.size})`).join('\n');
return [{
  json: {
    found: tables.length,
    tables: tables.map(t => t.tablename),
    summary: `Found ${tables.length} orphaned temp table(s) to drop:\n${list}`
  }
}];

const summary = $('Summarize Found').first().json;
const dropped = summary.found;

if (dropped === 0) {
  return [{ json: { status: 'ok', message: summary.summary } }];
}

const tableList = summary.tables.join(', ');
return [{
  json: {
    status: 'ok',
    message: `Successfully dropped ${dropped} orphaned temp table(s).`,
    dropped_tables: summary.tables
  }
}];
